

-- CReate databas
CREATE DATABASE IF NOT EXISTS product_db
  CHARACTER SET utf8mb4
  COLLATE utf8mb4_unicode_ci;

USE product_db;


-- main TABLE
CREATE TABLE IF NOT EXISTS products (
    id            INT            AUTO_INCREMENT PRIMARY KEY,
    brand         VARCHAR(50)    DEFAULT 'Montana',
    product_name  VARCHAR(150)   NOT NULL,
    content_ml    INT,
    color_name    VARCHAR(100),
    series        VARCHAR(50),
    code          VARCHAR(20),
    hex           VARCHAR(7),
    cmyk          VARCHAR(50),
    rgb           VARCHAR(30),
    pressure_lvl  VARCHAR(20),
    type          VARCHAR(50),
    type_finish   VARCHAR(50),
    price         DECIMAL(10,2)  DEFAULT 0.00,
    amount        INT            DEFAULT 0,
    stock         INT            DEFAULT 10
) ENGINE=InnoDB;


-- DATa



-- VIews

-- Kompakt visning (terminalvennlig)
CREATE OR REPLACE VIEW v_compact AS
SELECT
    id,
    product_name,
    content_ml AS ml,
    color_name AS color,
    COALESCE(CONCAT(series, ' ', code), '') AS ref,
    hex,
    pressure_lvl AS pressure,
    type,
    price,
    stock
FROM products;


-- Vis gruppert etter produktnavn (hvor mange farger hvert produkt har)
CREATE OR REPLACE VIEW v_summary AS
SELECT
    product_name,
    content_ml AS ml,
    COUNT(*) AS colors,
    pressure_lvl AS pressure,
    type
FROM products
GROUP BY product_name, content_ml, pressure_lvl, type
ORDER BY content_ml, product_name;


